import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { 
  FaSearch, FaUser, FaUpload, FaInfoCircle, FaHome, 
  FaGraduationCap, FaSignInAlt, FaUserPlus, FaBars, FaTimes,
  FaBook, FaLaptop, FaChartBar, FaBriefcase, FaCode,
  FaUserCircle, FaSignOutAlt, FaAngleDown
} from 'react-icons/fa';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [showSearchResults, setShowSearchResults] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState(null);
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(false);
  
  const navigate = useNavigate();
  const location = useLocation();

  // Scroll effect
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close menu on route change
  useEffect(() => {
    setIsMenuOpen(false);
    setActiveDropdown(null);
    setShowSearchResults(false);
  }, [location]);

  // Check login status
  useEffect(() => {
    const token = localStorage.getItem('study_portal_token');
    const userData = localStorage.getItem('study_portal_user');
    if (token && userData) {
      setIsLoggedIn(true);
      setUser(JSON.parse(userData));
    }
  }, []);

  // Fetch courses for dropdown
  useEffect(() => {
    fetchCourses();
  }, []);

  // Debounced search
  useEffect(() => {
    const timer = setTimeout(() => {
      if (searchQuery.length > 2) {
        performSearch();
      } else {
        setSearchResults([]);
      }
    }, 300);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const fetchCourses = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/courses');
      const data = await response.json();
      if (data.success) {
        setCourses(data.courses.slice(0, 6));
      } else {
        // Fallback courses
        setCourses([
          { id: 1, name: 'B.Tech', icon: '💻', code: 'BTECH', students: 1234 },
          { id: 2, name: 'BCA', icon: '📱', code: 'BCA', students: 2345 },
          { id: 3, name: 'BBA', icon: '📊', code: 'BBA', students: 3456 },
          { id: 4, name: 'MBA', icon: '🎓', code: 'MBA', students: 4567 },
          { id: 5, name: 'MCA', icon: '💼', code: 'MCA', students: 5678 },
          { id: 6, name: 'B.Com', icon: '💰', code: 'BCOM', students: 6789 },
        ]);
      }
    } catch (error) {
      // Fallback courses
      setCourses([
        { id: 1, name: 'B.Tech', icon: '💻', code: 'BTECH', students: 1234 },
        { id: 2, name: 'BCA', icon: '📱', code: 'BCA', students: 2345 },
        { id: 3, name: 'BBA', icon: '📊', code: 'BBA', students: 3456 },
        { id: 4, name: 'MBA', icon: '🎓', code: 'MBA', students: 4567 },
        { id: 5, name: 'MCA', icon: '💼', code: 'MCA', students: 5678 },
      ]);
    }
  };

  const performSearch = async () => {
    setLoading(true);
    try {
      const response = await fetch(`http://localhost:5000/api/search?q=${searchQuery}`);
      const data = await response.json();
      if (data.success) {
        setSearchResults(data.results.slice(0, 5));
      } else {
        // Fallback search results
        setSearchResults([
          { id: 1, type: 'course', title: 'BCA', description: 'Bachelor of Computer Applications' },
          { id: 2, type: 'notes', title: 'C Programming Notes', description: 'Complete C programming notes' },
          { id: 3, type: 'pyq', title: 'B.Tech PYQs 2024', description: 'Previous year question papers' },
        ]);
      }
    } catch (error) {
      // Fallback search results
      setSearchResults([
        { id: 1, type: 'course', title: 'BCA', description: 'Bachelor of Computer Applications' },
        { id: 2, type: 'notes', title: 'C Programming Notes', description: 'Complete C programming notes' },
        { id: 3, type: 'pyq', title: 'B.Tech PYQs 2024', description: 'Previous year question papers' },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setShowSearchResults(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('study_portal_user');
    setIsLoggedIn(false);
    setUser(null);
    navigate('/');
  };

  // ✅ Nav items - Home, Courses, Upload, About (order sahi)
  const navItems = [
    { name: 'Home', icon: <FaHome />, path: '/' },
    { name: 'Courses', icon: <FaGraduationCap />, path: '/courses', hasDropdown: true },
    { name: 'Upload', icon: <FaUpload />, path: '/upload' },
    { name: 'About', icon: <FaInfoCircle />, path: '/about' },
  ];

  // ✅ Attractive styles
  const styles = {
    navbar: {
      background: isScrolled 
        ? 'linear-gradient(135deg, #667eea 0%, #764ba2 50%, #4f46e5 100%)' 
        : 'linear-gradient(135deg, #4f46e5 0%, #667eea 50%, #7c3aed 100%)',
      backdropFilter: isScrolled ? 'blur(10px)' : 'none',
      padding: '0.8rem 2rem',
      position: 'sticky',
      top: 0,
      zIndex: 1000,
      transition: 'all 0.3s ease',
      boxShadow: isScrolled 
        ? '0 10px 30px rgba(79, 70, 229, 0.4)' 
        : '0 4px 15px rgba(0, 0, 0, 0.2)',
      borderBottom: '3px solid rgba(255, 255, 255, 0.2)'
    },
    container: {
      maxWidth: '1400px',
      margin: '0 auto',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      gap: '1rem'
    },
    logo: {
      color: 'white',
      fontSize: '1.6rem',
      fontWeight: '800',
      textDecoration: 'none',
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      background: 'rgba(255, 255, 255, 0.15)',
      padding: '0.5rem 1.2rem',
      borderRadius: '50px',
      transition: 'all 0.3s',
      border: '2px solid rgba(255, 255, 255, 0.3)',
      boxShadow: '0 4px 15px rgba(0, 0, 0, 0.2)',
      '&:hover': {
        background: 'rgba(255, 255, 255, 0.25)',
        transform: 'translateY(-2px) scale(1.02)',
        boxShadow: '0 8px 25px rgba(79, 70, 229, 0.4)'
      }
    },
    logoIcon: {
      fontSize: '2.2rem',
      background: 'linear-gradient(135deg, #fbbf24, #f59e0b)',
      padding: '0.5rem',
      borderRadius: '50%',
      boxShadow: '0 4px 10px rgba(251, 191, 36, 0.4)'
    },
    // ✅ Search bar - About ke baad (right side)
    searchContainer: {
      position: 'relative',
      flex: 1,
      maxWidth: '400px',
      marginLeft: 'auto',
      marginRight: '1rem'
    },
    searchForm: {
      display: 'flex',
      alignItems: 'center',
      background: 'rgba(255, 255, 255, 0.2)',
      borderRadius: '50px',
      border: '2px solid rgba(255, 255, 255, 0.3)',
      transition: 'all 0.3s',
      boxShadow: '0 4px 15px rgba(0, 0, 0, 0.1)',
      '&:focus-within': {
        background: 'white',
        borderColor: '#fbbf24',
        boxShadow: '0 8px 25px rgba(251, 191, 36, 0.3)',
        transform: 'scale(1.02)'
      }
    },
    searchInput: {
      flex: 1,
      padding: '0.8rem 1.5rem',
      background: 'transparent',
      border: 'none',
      color: 'white',
      fontSize: '0.95rem',
      outline: 'none',
      '&::placeholder': {
        color: 'rgba(255, 255, 255, 0.8)',
        fontWeight: '400'
      },
      '&:focus': {
        color: '#333'
      }
    },
    searchButton: {
      background: 'linear-gradient(135deg, #fbbf24, #f59e0b)',
      border: 'none',
      borderRadius: '0 50px 50px 0',
      padding: '0.8rem 1.5rem',
      color: '#4f46e5',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      fontWeight: '700',
      fontSize: '0.95rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: 'linear-gradient(135deg, #f59e0b, #fbbf24)',
        transform: 'scale(1.05)',
        boxShadow: '0 4px 15px rgba(251, 191, 36, 0.5)'
      }
    },
    searchResults: {
      position: 'absolute',
      top: '100%',
      left: 0,
      right: 0,
      background: 'white',
      borderRadius: '20px',
      boxShadow: '0 20px 50px rgba(0,0,0,0.2)',
      marginTop: '0.8rem',
      maxHeight: '400px',
      overflowY: 'auto',
      zIndex: 1000,
      border: '2px solid #fbbf24',
      animation: 'slideDown 0.3s ease'
    },
    searchResultItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '1rem',
      padding: '1rem 1.5rem',
      borderBottom: '1px solid #e2e8f0',
      cursor: 'pointer',
      transition: 'all 0.2s',
      '&:hover': {
        background: '#fef3c7',
        transform: 'translateX(5px)'
      }
    },
    navLinks: {
      display: 'flex',
      gap: '0.3rem',
      alignItems: 'center'
    },
    link: {
      color: 'white',
      textDecoration: 'none',
      padding: '0.7rem 1.2rem',
      borderRadius: '30px',
      transition: 'all 0.3s',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      fontSize: '1rem',
      fontWeight: '600',
      cursor: 'pointer',
      background: 'transparent',
      border: '2px solid transparent',
      position: 'relative'
    },
    activeLink: {
      background: 'rgba(255, 255, 255, 0.2)',
      border: '2px solid rgba(255, 255, 255, 0.5)',
      boxShadow: '0 4px 10px rgba(0, 0, 0, 0.2)'
    },
    dropdownWrapper: {
      position: 'relative'
    },
    dropdownMenu: {
      position: 'absolute',
      top: '100%',
      left: 0,
      minWidth: '450px',
      background: 'white',
      borderRadius: '20px',
      boxShadow: '0 20px 50px rgba(0,0,0,0.2)',
      padding: '1.2rem',
      marginTop: '0.8rem',
      zIndex: 1000,
      animation: 'slideDown 0.3s ease',
      border: '2px solid #fbbf24'
    },
    dropdownGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '0.8rem'
    },
    dropdownItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      padding: '0.8rem',
      borderRadius: '12px',
      cursor: 'pointer',
      transition: 'all 0.2s',
      background: '#f8fafc',
      border: '1px solid #e2e8f0',
      '&:hover': {
        background: '#fef3c7',
        borderColor: '#fbbf24',
        transform: 'translateY(-2px)',
        boxShadow: '0 4px 10px rgba(251, 191, 36, 0.2)'
      }
    },
    courseIcon: {
      fontSize: '1.8rem',
      width: '45px',
      height: '45px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(135deg, #4f46e5, #7c3aed)',
      color: 'white',
      borderRadius: '10px',
      boxShadow: '0 4px 8px rgba(79, 70, 229, 0.3)'
    },
    userMenu: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      marginLeft: '0.5rem'
    },
    userAvatar: {
      width: '45px',
      height: '45px',
      borderRadius: '50%',
      background: 'linear-gradient(135deg, #fbbf24, #f59e0b)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      color: '#4f46e5',
      fontSize: '1.3rem',
      fontWeight: 'bold',
      cursor: 'pointer',
      border: '3px solid white',
      boxShadow: '0 4px 10px rgba(0, 0, 0, 0.2)',
      transition: 'all 0.3s',
      '&:hover': {
        transform: 'scale(1.1) rotate(5deg)',
        boxShadow: '0 8px 20px rgba(251, 191, 36, 0.4)'
      }
    },
    // ✅ Auth buttons - sabse last mein
    authButtons: {
      display: 'flex',
      gap: '0.8rem',
      marginLeft: '0.5rem'
    },
    loginBtn: {
      background: 'transparent',
      border: '2px solid white',
      color: 'white',
      padding: '0.7rem 1.5rem',
      borderRadius: '30px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '0.95rem',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      transition: 'all 0.3s',
      boxShadow: '0 4px 10px rgba(0, 0, 0, 0.1)',
      '&:hover': {
        background: 'white',
        color: '#4f46e5',
        transform: 'translateY(-2px) scale(1.05)',
        boxShadow: '0 8px 20px rgba(255, 255, 255, 0.3)'
      }
    },
    registerBtn: {
      background: 'linear-gradient(135deg, #fbbf24, #f59e0b)',
      border: 'none',
      color: '#4f46e5',
      padding: '0.7rem 1.5rem',
      borderRadius: '30px',
      cursor: 'pointer',
      fontWeight: '700',
      fontSize: '0.95rem',
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      transition: 'all 0.3s',
      boxShadow: '0 4px 15px rgba(251, 191, 36, 0.4)',
      '&:hover': {
        background: 'linear-gradient(135deg, #f59e0b, #fbbf24)',
        transform: 'translateY(-2px) scale(1.05)',
        boxShadow: '0 10px 25px rgba(251, 191, 36, 0.6)'
      }
    },
    mobileBtn: {
      display: 'none',
      background: 'rgba(255, 255, 255, 0.2)',
      border: '2px solid white',
      color: 'white',
      fontSize: '1.5rem',
      cursor: 'pointer',
      padding: '0.7rem 1rem',
      borderRadius: '12px',
      transition: 'all 0.3s',
      '&:hover': {
        background: 'white',
        color: '#4f46e5',
        transform: 'rotate(90deg)'
      }
    }
  };

  return (
    <nav style={styles.navbar}>
      <div style={styles.container}>
        {/* Logo */}
        <Link to="/" style={styles.logo}>
          <span style={styles.logoIcon}>📚</span>
          <span>Study Portal</span>
        </Link>

        {/* Desktop Menu */}
        <div style={{ display: 'flex', alignItems: 'center', flex: 1, justifyContent: 'flex-end' }}>
          <div style={styles.navLinks}>
            {navItems.map(item => (
              item.hasDropdown ? (
                <div key={item.name} style={styles.dropdownWrapper}>
                  <button
                    style={{
                      ...styles.link,
                      ...(activeDropdown === 'courses' ? styles.activeLink : {})
                    }}
                    onClick={() => setActiveDropdown(activeDropdown === 'courses' ? null : 'courses')}
                    onMouseEnter={() => setActiveDropdown('courses')}
                  >
                    {item.icon} {item.name} <FaAngleDown style={{ marginLeft: '0.2rem' }} />
                  </button>

                  {activeDropdown === 'courses' && (
                    <div 
                      style={styles.dropdownMenu}
                      onMouseLeave={() => setActiveDropdown(null)}
                    >
                      <div style={styles.dropdownGrid}>
                        {courses.map(course => (
                          <div
                            key={course.id}
                            style={styles.dropdownItem}
                            onClick={() => {
                              navigate(`/course/${course.id}`);
                              setActiveDropdown(null);
                            }}
                          >
                            <div style={styles.courseIcon}>
                              {course.icon}
                            </div>
                            <div>
                              <div style={{ fontWeight: '700', color: '#1e293b' }}>{course.name}</div>
                              <div style={{ fontSize: '0.7rem', color: '#64748b' }}>
                                {course.students} students
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                      <Link 
                        to="/courses" 
                        style={{
                          display: 'block',
                          textAlign: 'center',
                          padding: '0.8rem',
                          marginTop: '0.8rem',
                          color: '#4f46e5',
                          textDecoration: 'none',
                          fontWeight: '700',
                          borderTop: '2px solid #e2e8f0'
                        }}
                        onClick={() => setActiveDropdown(null)}
                      >
                        View All Courses →
                      </Link>
                    </div>
                  )}
                </div>
              ) : (
                <Link
                  key={item.name}
                  to={item.path}
                  style={{
                    ...styles.link,
                    ...(location.pathname === item.path ? styles.activeLink : {})
                  }}
                >
                  {item.icon} {item.name}
                </Link>
              )
            ))}
          </div>

          {/* ✅ Search Bar - About ke baad */}
          <div style={styles.searchContainer}>
            <form onSubmit={handleSearch} style={styles.searchForm}>
              <input
                type="text"
                placeholder="Search courses, notes, PYQs..."
                value={searchQuery}
                onChange={(e) => {
                  setSearchQuery(e.target.value);
                  setShowSearchResults(true);
                }}
                onFocus={() => setShowSearchResults(true)}
                style={styles.searchInput}
              />
              <button type="submit" style={styles.searchButton}>
                <FaSearch /> Search
              </button>
            </form>

            {/* Search Results */}
            {showSearchResults && searchQuery.length > 2 && (
              <div style={styles.searchResults}>
                {loading ? (
                  <div style={{ padding: '1.5rem', textAlign: 'center', color: '#4f46e5' }}>
                    <div className="spinner"></div>
                    Searching...
                  </div>
                ) : searchResults.length > 0 ? (
                  searchResults.map(result => (
                    <div
                      key={result.id}
                      style={styles.searchResultItem}
                      onClick={() => {
                        navigate(`/${result.type}/${result.id}`);
                        setShowSearchResults(false);
                        setSearchQuery('');
                      }}
                    >
                      <span style={{ fontSize: '1.5rem' }}>
                        {result.type === 'course' ? '📚' : 
                         result.type === 'notes' ? '📝' : '📄'}
                      </span>
                      <div>
                        <div style={{ fontWeight: '700', color: '#1e293b' }}>{result.title}</div>
                        <div style={{ fontSize: '0.8rem', color: '#64748b' }}>{result.description}</div>
                      </div>
                    </div>
                  ))
                ) : (
                  <div style={{ padding: '2rem', textAlign: 'center', color: '#64748b' }}>
                    <FaSearch style={{ fontSize: '2rem', marginBottom: '0.5rem', opacity: 0.5 }} />
                    <div>No results found</div>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* ✅ User Menu / Auth Buttons - Last mein */}
          {isLoggedIn ? (
            <div style={styles.userMenu}>
              <div 
                style={styles.userAvatar}
                onClick={() => navigate('/profile')}
              >
                {user?.name?.charAt(0) || <FaUserCircle />}
              </div>
              <button 
                onClick={handleLogout}
                style={styles.loginBtn}
              >
                <FaSignOutAlt /> Logout
              </button>
            </div>
          ) : (
            <div style={styles.authButtons}>
              <button style={styles.loginBtn} onClick={() => navigate('/login')}>
                <FaSignInAlt /> Login
              </button>
              <button style={styles.registerBtn} onClick={() => navigate('/register')}>
                <FaUserPlus /> Register
              </button>
            </div>
          )}
        </div>

        {/* Mobile Menu Button */}
        <button style={styles.mobileBtn} onClick={() => setIsMenuOpen(!isMenuOpen)}>
          {isMenuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>

      {/* CSS Animations */}
      <style>
        {`
          @keyframes slideDown {
            from {
              opacity: 0;
              transform: translateY(-20px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
          
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
          
          .spinner {
            width: 30px;
            height: 30px;
            border: 3px solid #e2e8f0;
            border-top: 3px solid #4f46e5;
            border-radius: 50%;
            animation: spin 1s linear infinite;
            margin: 0 auto 0.5rem;
          }
          
          button, a {
            transition: all 0.3s ease;
          }
        `}
      </style>
    </nav>
  );
};

export default Navbar;
